{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleMultilineStringClosingQuotesTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

internal class IndentationRuleMultilineStringClosingQuotesTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a raw string literal returned from a function body expression then align closing quotes with function`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android=\"http://schemas.android.com/apk/res/android\"/>
            $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a raw string literal returned from a return statement then align closing quotes with return statement`() {
        val code =
            """
            fun foo2(): String {
                return $MULTILINE_STRING_QUOTE
                    <!--suppress XmlUnusedNamespaceDeclaration -->
                    <manifest xmlns:android=\"http://schemas.android.com/apk/res/android\"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

